public convertMarkdownToHtml(md: string): string {
    if (!md) return '';
    const lines = md.split(/\r?\n/);
    let html = '';
    let inList = false;
    let listType: 'ul' | 'ol' | null = null;

    const closeList = () => {
      if (inList) {
        html += listType === 'ul' ? '</ul>' : '</ol>';
        inList = false;
        listType = null;
      }
    };

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) {
        closeList();
        continue;
      }

      // Headers (e.g., # H1)
      const headerMatch = line.match(/^(#{1,6})\s+(.*)$/);
      if (headerMatch) {
        closeList();
        const level = headerMatch[1].length;
        html += `<h${level}>${this.parseInlineMarkdown(headerMatch[2])}</h${level}>`;
        continue;
      }

      // Unordered list item
      const ulMatch = line.match(/^([*\-+])\s+(.*)$/);
      if (ulMatch) {
        if (!inList || listType !== 'ul') {
          closeList();
          html += '<ul>';
          inList = true;
          listType = 'ul';
        }
        html += `<li>${this.parseInlineMarkdown(ulMatch[2])}</li>`;
        continue;
      }

      // Ordered list item
      const olMatch = line.match(/^(\d+)\.\s+(.*)$/);
      if (olMatch) {
        if (!inList || listType !== 'ol') {
          closeList();
          html += '<ol>';
          inList = true;
          listType = 'ol';
        }
        html += `<li>${this.parseInlineMarkdown(olMatch[2])}</li>`;
        continue;
      }

      // Blockquote
      const quoteMatch = line.match(/^>\s+(.*)$/);
      if (quoteMatch) {
        closeList();
        html += `<blockquote>${this.parseInlineMarkdown(quoteMatch[1])}</blockquote>`;
        continue;
      }

      // Regular paragraph
      closeList();
      html += `<p>${this.parseInlineMarkdown(line)}</p>`;
    }

    closeList();
    return html;
  }

